package com.companionlink.servlet.volunteer;
import com.companionlink.dao.VisitDAO; import com.companionlink.model.Visit; import com.companionlink.servlet.BaseServlet; import jakarta.servlet.*; import jakarta.servlet.annotation.WebServlet; import jakarta.servlet.http.*; import java.io.IOException;
@WebServlet("/volunteer/complete") public class CompleteVisitServlet extends BaseServlet { private final VisitDAO dao=new VisitDAO(); protected void doGet(HttpServletRequest r,HttpServletResponse h)throws ServletException,IOException{Visit v=dao.findById(Integer.parseInt(r.getParameter("visitId")));r.setAttribute("visit",v);forward(r,h,"volunteer/complete");} protected void doPost(HttpServletRequest r,HttpServletResponse h)throws IOException{int dur=Integer.parseInt(r.getParameter("duration")); if(dur<=0){fail(r,h,"/volunteer/schedule","Duration must be more than 0.");return;} dao.completeVisit(Integer.parseInt(r.getParameter("visitId")),currentUser(r).getId(),dur,r.getParameter("notes"));ok(r,h,"/volunteer/schedule","Visit completed. Senior can now rate you.");}}
